class OutputGuardrails:
    def __init__(self):
        self.validators: list[Callable] = []
        self.filters: list[Callable] = []

    def add_validator(self, validator: Callable):
        self.validators.append(validator)

    def validate(self, output: str) -> tuple[bool, list[str]]:
        errors = []
        for validator in self.validators:
            is_valid, error = validator(output)
            if not is_valid:
                errors.append(error)
        return len(errors) == 0, errors

    def filter(self, output: str) -> str:
        filtered = output
        for filter_func in self.filters:
            filtered = filter_func(filtered)
        return filtered

import json, re
from typing import Tuple

def validate_json_format(output: str) -> Tuple[bool, str]:
    try:
        json.loads(output)
        return True, ""
    except json.JSONDecodeError as e:
        return False, f"Invalid JSON: {e}"

def validate_length(max_length: int):
    def validator(output: str) -> Tuple[bool, str]:
        if len(output) > max_length:
            return False, f"Output exceeds {max_length} characters"
        return True, ""
    return validator

def filter_remove_urls(output: str) -> str:
    return re.sub(r'https?://\S+', '[URL REMOVED]', output)

class HallucinationDetector:
    def __init__(self, client, model: str = "gpt-4o"):
        self.client = client
        self.model = model

    def detect_hallucinations(self, output: str, context: str) -> dict:
        prompt = f"""Context:\n{context}\n\nResponse:\n{output}\n\n
Return JSON: {{"has_hallucinations": bool, "hallucinated_claims": [str], "confidence": float}}"""
        response = self.client.chat.completions.create(
            model=self.model,
            messages=[{"role": "user", "content": prompt}],
            response_format={"type": "json_object"}
        )
        return json.loads(response.choices[0].message.content)
